    // ============================================
    // WebViewClient - Navigation & Error Handling
    // ============================================
    private class HybridWebViewClient extends WebViewClient {

        @Override
        public boolean shouldOverrideUrlLoading(WebView view, WebResourceRequest request) {
            String url = request.getUrl().toString();

            // Keep our domain in WebView
            if (url.contains("your-mobile-website.com")) {
                return false;
            }

            // Handle special schemes
            if (url.startsWith("tel:")) {
                startActivity(new Intent(Intent.ACTION_DIAL, Uri.parse(url)));
                return true;
            }

            if (url.startsWith("mailto:")) {
                startActivity(new Intent(Intent.ACTION_SENDTO, Uri.parse(url)));
                return true;
            }

            if (url.startsWith("sms:")) {
                startActivity(new Intent(Intent.ACTION_VIEW, Uri.parse(url)));
                return true;
            }

            // Handle payment deep links
            if (url.startsWith("upi:") || url.contains("pay.google.com")) {
                try {
                    startActivity(new Intent(Intent.ACTION_VIEW, Uri.parse(url)));
                } catch (Exception e) {
                    Toast.makeText(MainActivity.this, "Payment app not found", Toast.LENGTH_SHORT).show();
                }
                return true;
            }

            // Open external URLs in browser
            startActivity(new Intent(Intent.ACTION_VIEW, Uri.parse(url)));
            return true;
        }

        @Override
        public void onPageStarted(WebView view, String url, Bitmap favicon) {
            super.onPageStarted(view, url, favicon);
            progressBar.setVisibility(ProgressBar.VISIBLE);
        }

        @Override
        public void onPageFinished(WebView view, String url) {
            super.onPageFinished(view, url);
            progressBar.setVisibility(ProgressBar.GONE);
            swipeRefreshLayout.setRefreshing(false);

            // Inject bridge availability notification to web
            injectBridgeReadyEvent();
        }

        @Override
        public void onReceivedError(WebView view, WebResourceRequest request, WebResourceError error) {
            super.onReceivedError(view, request, error);
            if (request.isForMainFrame()) {
                Log.e(TAG, "WebView error: " + error.getDescription());
                loadErrorPage(view);
            }
        }

        private void loadErrorPage(WebView view) {
            String errorHtml = "<!DOCTYPE html><html><head>" +
                    "<meta name='viewport' content='width=device-width, initial-scale=1.0'>" +
                    "<style>" +
                    "body { font-family: -apple-system, sans-serif; display: flex; " +
                    "justify-content: center; align-items: center; min-height: 100vh; " +
                    "margin: 0; background: #f5f5f5; text-align: center; }" +
                    ".container { padding: 20px; }" +
                    "h2 { color: #333; }" +
                    "p { color: #666; }" +
                    "button { background: #007AFF; color: white; border: none; " +
                    "padding: 12px 24px; border-radius: 8px; font-size: 16px; cursor: pointer; }" +
                    "</style></head><body>" +
                    "<div class='container'>" +
                    "<h2>Connection Error</h2>" +
                    "<p>Unable to connect. Please check your internet connection.</p>" +
                    "<button onclick='window.location.reload()'>Retry</button>" +
                    "</div></body></html>";
            view.loadDataWithBaseURL(null, errorHtml, "text/html", "UTF-8", null);
        }
    }

    // ============================================
    // WebChromeClient - Advanced Features
    // ============================================
    private class HybridWebChromeClient extends WebChromeClient {

        @Override
        public void onProgressChanged(WebView view, int newProgress) {
            progressBar.setProgress(newProgress);
            if (newProgress == 100) {
                progressBar.setVisibility(ProgressBar.GONE);
            }
        }

        @Override
        public void onGeolocationPermissionsShowPrompt(String origin,
                                                        GeolocationPermissions.Callback callback) {
            if (checkLocationPermission()) {
                callback.invoke(origin, true, false);
            } else {
                ActivityCompat.requestPermissions(MainActivity.this,
                        new String[]{
                                Manifest.permission.ACCESS_FINE_LOCATION,
                                Manifest.permission.ACCESS_COARSE_LOCATION
                        },
                        PERMISSION_REQUEST_LOCATION);
                // Store callback for later use after permission result
                pendingGeolocationCallback = callback;
                pendingGeolocationOrigin = origin;
            }
        }

        @Override
        public boolean onShowFileChooser(WebView webView,
                                          ValueCallback<Uri[]> filePathCallback,
                                          FileChooserParams fileChooserParams) {
            if (fileUploadCallback != null) {
                fileUploadCallback.onReceiveValue(null);
            }
            fileUploadCallback = filePathCallback;

            // Check if accepting images - offer camera option
            String[] acceptTypes = fileChooserParams.getAcceptTypes();
            boolean acceptsImages = false;
            for (String type : acceptTypes) {
                if (type != null && (type.startsWith("image/") || type.equals("image/*"))) {
                    acceptsImages = true;
                    break;
                }
            }

            if (acceptsImages && fileChooserParams.isCaptureEnabled()) {
                if (checkCameraPermission()) {
                    launchCameraForFileUpload();
                } else {
                    requestCameraPermission();
                }
            } else {
                Intent intent = fileChooserParams.createIntent();
                fileChooserLauncher.launch(intent);
            }

            return true;
        }

        @Override
        public boolean onConsoleMessage(ConsoleMessage consoleMessage) {
            Log.d(TAG, "WebConsole: " + consoleMessage.message()
                    + " -- line " + consoleMessage.lineNumber()
                    + " of " + consoleMessage.sourceId());
            return true;
        }
    }

    // ============================================
    // Location Handling
    // ============================================
    private GeolocationPermissions.Callback pendingGeolocationCallback;
    private String pendingGeolocationOrigin;
    private String pendingLocationCallback;

    private boolean checkLocationPermission() {
        return ContextCompat.checkSelfPermission(this, Manifest.permission.ACCESS_FINE_LOCATION)
                == PackageManager.PERMISSION_GRANTED;
    }

    private void requestLocationPermission(String callbackFunction) {
        pendingLocationCallback = callbackFunction;
        ActivityCompat.requestPermissions(this,
                new String[]{
                        Manifest.permission.ACCESS_FINE_LOCATION,
                        Manifest.permission.ACCESS_COARSE_LOCATION
                },
                PERMISSION_REQUEST_LOCATION);
    }

    @SuppressLint("MissingPermission")
    private void fetchLocation(String callbackFunction) {
        CancellationTokenSource cancellationTokenSource = new CancellationTokenSource();
        fusedLocationClient.getCurrentLocation(Priority.PRIORITY_HIGH_ACCURACY,
                        cancellationTokenSource.getToken())
                .addOnSuccessListener(this, location -> {
                    if (location != null) {
                        String locationJson = String.format(Locale.US,
                                "{\"latitude\": %f, \"longitude\": %f, \"accuracy\": %f, \"timestamp\": %d}",
                                location.getLatitude(),
                                location.getLongitude(),
                                location.getAccuracy(),
                                location.getTime());
                        sendCallbackToJs(callbackFunction, locationJson);
                    } else {
                        sendCallbackToJs(callbackFunction,
                                "{\"error\": \"Location unavailable\"}");
                    }
                })
                .addOnFailureListener(this, e -> {
                    sendCallbackToJs(callbackFunction,
                            "{\"error\": \"" + e.getMessage() + "\"}");
                });
    }

    // ============================================
    // Camera Handling
    // ============================================
    private String pendingCameraCallback;

    private boolean checkCameraPermission() {
        return ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA)
                == PackageManager.PERMISSION_GRANTED;
    }

    private void requestCameraPermission() {
        ActivityCompat.requestPermissions(this,
                new String[]{Manifest.permission.CAMERA},
                PERMISSION_REQUEST_CAMERA);
    }

    private void launchCamera(String callbackFunction) {
        pendingCameraCallback = callbackFunction;
        Intent takePictureIntent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
        if (takePictureIntent.resolveActivity(getPackageManager()) != null) {
            File photoFile = null;
            try {
                photoFile = createImageFile();
            } catch (IOException ex) {
                Log.e(TAG, "Error creating image file", ex);
            }

            if (photoFile != null) {
                Uri photoURI = FileProvider.getUriForFile(this,
                        getPackageName() + ".fileprovider",
                        photoFile);
                takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI);
                cameraLauncher.launch(takePictureIntent);
            }
        }
    }

    private void launchCameraForFileUpload() {
        Intent takePictureIntent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
        if (takePictureIntent.resolveActivity(getPackageManager()) != null) {
            File photoFile = null;
            try {
                photoFile = createImageFile();
            } catch (IOException ex) {
                Log.e(TAG, "Error creating image file", ex);
                if (fileUploadCallback != null) {
                    fileUploadCallback.onReceiveValue(null);
                    fileUploadCallback = null;
                }
                return;
            }

            Uri photoURI = FileProvider.getUriForFile(this,
                    getPackageName() + ".fileprovider",
                    photoFile);
            takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI);
            cameraLauncher.launch(takePictureIntent);
        }
    }

    private File createImageFile() throws IOException {
        String timeStamp = new SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(new Date());
        String imageFileName = "JPEG_" + timeStamp + "_";
        File storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES);
        File image = File.createTempFile(imageFileName, ".jpg", storageDir);
        currentPhotoPath = image.getAbsolutePath();
        return image;
    }

