    // ============================================
    // Utility Methods
    // ============================================
    private void sendCallbackToJs(String callbackFunction, String data) {
        runOnUiThread(() -> {
            String jsCall = String.format("javascript:if(typeof %s === 'function') { %s(%s); }",
                    callbackFunction, callbackFunction, data);
            webView.evaluateJavascript(jsCall, null);
        });
    }

    private void injectBridgeReadyEvent() {
        String js = "javascript:(function() {" +
                "  var event = new CustomEvent('NativeBridgeReady', {" +
                "    detail: { platform: 'android', version: '" + android.os.Build.VERSION.RELEASE + "' }" +
                "  });" +
                "  document.dispatchEvent(event);" +
                "  window.isNativeApp = true;" +
                "  window.nativePlatform = 'android';" +
                "  console.log('NativeBridge is ready');" +
                "})();";
        webView.evaluateJavascript(js, null);
    }

    // ============================================
    // Permission Results
    // ============================================
    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions,
                                            @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);

        switch (requestCode) {
            case PERMISSION_REQUEST_LOCATION:
                if (grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                    // Handle geolocation callback from WebChromeClient
                    if (pendingGeolocationCallback != null) {
                        pendingGeolocationCallback.invoke(pendingGeolocationOrigin, true, false);
                        pendingGeolocationCallback = null;
                        pendingGeolocationOrigin = null;
                    }
                    // Handle location callback from JavaScript bridge
                    if (pendingLocationCallback != null) {
                        fetchLocation(pendingLocationCallback);
                        pendingLocationCallback = null;
                    }
                } else {
                    if (pendingGeolocationCallback != null) {
                        pendingGeolocationCallback.invoke(pendingGeolocationOrigin, false, false);
                        pendingGeolocationCallback = null;
                    }
                    if (pendingLocationCallback != null) {
                        sendCallbackToJs(pendingLocationCallback,
                                "{\"error\": \"Location permission denied\"}");
                        pendingLocationCallback = null;
                    }
                }
                break;

            case PERMISSION_REQUEST_CAMERA:
                if (grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                    if (fileUploadCallback != null) {
                        launchCameraForFileUpload();
                    } else if (pendingCameraCallback != null) {
                        launchCamera(pendingCameraCallback);
                    }
                } else {
                    Toast.makeText(this, "Camera permission denied", Toast.LENGTH_SHORT).show();
                    if (fileUploadCallback != null) {
                        fileUploadCallback.onReceiveValue(null);
                        fileUploadCallback = null;
                    }
                }
                break;
        }
    }

